150→    private static void requestPostsForBlog(final long blogId,
151→                                            final UpdateAction updateAction,
152→                                            final ReaderActions.UpdateResultListener resultListener) {
153→        String path = "read/sites/" + blogId + "/posts/?meta=site,likes";
154→
155→        // append the date of the oldest cached post in this blog when requesting older posts
156→        if (updateAction == UpdateAction.REQUEST_OLDER) {
157→            String dateOldest = ReaderPostTable.getOldestPubDateInBlog(blogId);
158→            if (!TextUtils.isEmpty(dateOldest)) {
159→                path += "&before=" + UrlUtils.urlEncode(dateOldest);
160→            }
161→        }
162→
163→        com.wordpress.rest.RestRequest.Listener listener = new RestRequest.Listener() {
164→            @Override
165→            public void onResponse(JSONObject jsonObject) {
166→                handleUpdatePostsResponse(null, jsonObject, updateAction, resultListener);
167→            }
168→        };
169→        RestRequest.ErrorListener errorListener = new RestRequest.ErrorListener() {
170→            @Override
171→            public void onErrorResponse(VolleyError volleyError) {
172→                AppLog.e(AppLog.T.READER, volleyError);
173→                resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
174→            }
175→        };
