766→    /*
767→     * the column posts are sorted by depends on the type of tag stream being displayed:
768→     *
769→     * liked posts sort by the date the post was liked
770→     * followed posts sort by the date the post was published
771→     * search results sort by score
772→     * tagged posts sort by the date the post was tagged
773→     */
774→    private static String getSortColumnForTag(ReaderTag tag) {
775→        if (tag.isPostsILike()) {
776→            return "date_liked";
777→        } else if (tag.isFollowedSites()) {
778→            return "date_published";
779→        } else if (tag.tagType == ReaderTagType.SEARCH) {
780→            return "score";
781→        } else if (tag.isTagTopic() || tag.isBookmarked()) {
782→            return "date_tagged";
783→        } else {
784→            return "date_published";
785→        }
786→    }
