802→        int numDeleted = ReaderDatabase.getWritableDb().delete("tbl_posts", where, args);
803→        if (numDeleted > 0) {
804→            AppLog.d(AppLog.T.READER, "removed " + numDeleted + " posts older than gap marker");
805→            EventBus.getDefault().post(ReaderPostTableActionEnded.INSTANCE);
806→        }
807→    }
