809→    public static void setFollowStatusForPostsInBlog(long blogId, boolean isFollowed) {
810→        setFollowStatusForPosts(blogId, 0, isFollowed);
811→    }
812→
813→    public static void setFollowStatusForPostsInFeed(long feedId, boolean isFollowed) {
814→        setFollowStatusForPosts(0, feedId, isFollowed);
815→    }
