817→    private static void setFollowStatusForPosts(long blogId, long feedId, boolean isFollowed) {
818→        if (blogId == 0 && feedId == 0) {
819→            return;
820→        }
821→
822→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
823→        db.beginTransaction();
824→        try {
825→            if (blogId != 0) {
826→                String sql = "UPDATE tbl_posts SET is_followed=" + SqlUtils.boolToSql(isFollowed)
827→                             + " WHERE blog_id=?";
828→                db.execSQL(sql, new String[]{Long.toString(blogId)});
829→            } else {
830→                String sql = "UPDATE tbl_posts SET is_followed=" + SqlUtils.boolToSql(isFollowed)
831→                             + " WHERE feed_id=?";
832→                db.execSQL(sql, new String[]{Long.toString(feedId)});
833→            }
834→
835→
836→            // if blog/feed is no longer followed, remove its posts tagged with "Followed Sites" or "P2"
837→            if (!isFollowed) {
838→                if (blogId != 0) {
839→                    db.delete("tbl_posts", "blog_id=? AND (tag_name=? OR tag_name=?)",
840→                            new String[]{Long.toString(blogId), ReaderTag.TAG_TITLE_FOLLOWED_SITES,
841→                                    ReaderTag.TAG_SLUG_P2});
842→                } else {
843→                    db.delete("tbl_posts", "feed_id=? AND (tag_name=? OR tag_name=?)",
844→                            new String[]{Long.toString(feedId), ReaderTag.TAG_TITLE_FOLLOWED_SITES,
845→                                    ReaderTag.TAG_SLUG_P2});
846→                }
847→            }
848→
849→            db.setTransactionSuccessful();
850→            EventBus.getDefault().post(ReaderPostTableActionEnded.INSTANCE);
851→        } finally {
852→            db.endTransaction();
853→        }
854→    }
855→
856→    /**
857→     * Android's CursorWindow has a max size of 2MB per row which can be exceeded
858→     * with a very large text column, causing an IllegalStateException when the
859→     * row is read - prevent this by limiting the amount of text that's stored in
860→     * the text column - note that this situation very rarely occurs
861→     * http://bit.ly/2Fs7B78
862→     * http://bit.ly/2oOKCJc
863→     */
864→    private static final int MAX_TEXT_LEN = (1024 * 1024) / 2;
865→
866→    private static String maxText(final ReaderPost post) {
867→        if (post.getText().length() <= MAX_TEXT_LEN) {
868→            return post.getText();
869→        }
870→        // if the post has an excerpt (which should always be the case), store it as the full text
871→        // with a link to the full article
872→        if (post.hasExcerpt()) {
873→            AppLog.w(AppLog.T.READER, "reader post table > max text exceeded, storing excerpt");
874→            return "<p>" + post.getExcerpt() + "</p>"
875→                   + String.format("<p style='text-align:center'><a href='%s'>%s</a></p>",
876→                    post.getUrl(),
877→                    WordPress.getContext().getString(R.string.reader_label_view_original));
878→        } else {
879→            AppLog.w(AppLog.T.READER, "reader post table > max text exceeded, storing truncated text");
880→            return post.getText().substring(0, MAX_TEXT_LEN);
881→        }
882→    }
