 18→public class ReaderPostServiceStarter {
 19→    public static final String ARG_TAG = "tag";
 20→    public static final String ARG_ACTION = "action";
 21→    public static final String ARG_BLOG_ID = "blog_id";
 22→    public static final String ARG_FEED_ID = "feed_id";
 23→
 24→    public static final String ARG_TAG_PARAM_SLUG = "tag-slug";
 25→    public static final String ARG_TAG_PARAM_DISPLAY_NAME = "tag-display-name";
 26→    public static final String ARG_TAG_PARAM_TITLE = "tag-title";
 27→    public static final String ARG_TAG_PARAM_ENDPOINT = "tag-endpoint";
 28→    public static final String ARG_TAG_PARAM_TAGTYPE = "tag-type";
 29→
 30→    public enum UpdateAction {
 31→        REQUEST_NEWER, // request the newest posts for this tag/blog/feed
 32→        REQUEST_REFRESH, // request fresh data and get rid of the rest
 33→        REQUEST_OLDER, // request posts older than the oldest existing one for this tag/blog/feed
 34→        REQUEST_OLDER_THAN_GAP // request posts older than the one with the gap marker for this tag
 35→                               // (not supported for blog/feed)
 36→    }
 37→
 38→    /*
 39→     * update posts with the passed tag
 40→     */
 41→    public static void startServiceForTag(Context context, ReaderTag tag, UpdateAction action) {
 42→        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.O) {
 43→            Intent intent = new Intent(context, ReaderPostService.class);
 44→            intent.putExtra(ARG_TAG, tag);
 45→            intent.putExtra(ARG_ACTION, action);
 46→            context.startService(intent);
 47→        } else {
 48→            PersistableBundle extras = new PersistableBundle();
 49→            extras.putInt(ARG_ACTION, action.ordinal());
 50→            putReaderTagExtras(extras, tag);
 51→            doScheduleJobWithBundle(context, extras, JOB_READER_POST_SERVICE_ID_TAG + tag.getTagSlug().hashCode());
 52→        }
 53→    }
 54→
 55→    /*
 56→     * update posts in the passed blog
 57→     */
 58→    public static void startServiceForBlog(Context context, long blogId, UpdateAction action) {
 59→        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.O) {
 60→            Intent intent = new Intent(context, ReaderPostService.class);
 61→            intent.putExtra(ARG_BLOG_ID, blogId);
 62→            intent.putExtra(ARG_ACTION, action);
 63→            context.startService(intent);
 64→        } else {
 65→            PersistableBundle extras = new PersistableBundle();
 66→            extras.putLong(ARG_BLOG_ID, blogId);
 67→            extras.putInt(ARG_ACTION, action.ordinal());
 68→            doScheduleJobWithBundle(context, extras, JOB_READER_POST_SERVICE_ID_BLOG);
 69→        }
 70→    }
 71→
 72→    /*
 73→     * update posts in the passed feed
 74→     */
 75→    public static void startServiceForFeed(Context context, long feedId, UpdateAction action) {
 76→        if (Build.VERSION.SDK_INT < Build.VERSION_CODES.O) {
 77→            Intent intent = new Intent(context, ReaderPostService.class);
 78→            intent.putExtra(ARG_FEED_ID, feedId);
 79→            intent.putExtra(ARG_ACTION, action);
 80→            context.startService(intent);
 81→        } else {
 82→            PersistableBundle extras = new PersistableBundle();
 83→            extras.putLong(ARG_FEED_ID, feedId);
 84→            extras.putInt(ARG_ACTION, action.ordinal());
 85→            doScheduleJobWithBundle(context, extras, JOB_READER_POST_SERVICE_ID_FEED);
 86→        }
 87→    }
 88→
 89→    private static void doScheduleJobWithBundle(Context context, PersistableBundle extras, int jobId) {
 90→        // schedule the JobService here for API >= 26. The JobScheduler is available since API 21, but
 91→        // it's preferable to use it only since enforcement in API 26 to not break any old behavior
 92→        ComponentName componentName = new ComponentName(context, ReaderPostJobService.class);
 93→
 94→        JobInfo jobInfo = new JobInfo.Builder(jobId, componentName)
 95→                .setRequiresCharging(false)
 96→                .setRequiredNetworkType(JobInfo.NETWORK_TYPE_ANY)
 97→                .setOverrideDeadline(0) // if possible, try to run right away
 98→                .setExtras(extras)
 99→                .build();
100→
101→        JobScheduler jobScheduler = (JobScheduler) context.getSystemService(Context.JOB_SCHEDULER_SERVICE);
102→        int resultCode = jobScheduler.schedule(jobInfo);
103→        if (resultCode == JobScheduler.RESULT_SUCCESS) {
104→            AppLog.i(AppLog.T.READER, "reader post service > job scheduled");
105→        } else {
106→            AppLog.e(AppLog.T.READER, "reader post service > job could not be scheduled");
107→        }
108→    }
109→
110→    private static void putReaderTagExtras(PersistableBundle extras, ReaderTag tag) {
111→        extras.putString(ARG_TAG_PARAM_SLUG, tag.getTagSlug());
112→        extras.putString(ARG_TAG_PARAM_DISPLAY_NAME, tag.getTagDisplayName());
113→        extras.putString(ARG_TAG_PARAM_TITLE, tag.getTagTitle());
114→        extras.putString(ARG_TAG_PARAM_ENDPOINT, tag.getEndpoint());
115→        extras.putInt(ARG_TAG_PARAM_TAGTYPE, tag.tagType.toInt());
116→    }
117→}
